-- ============================================================
-- Migration 020 — Section 6 (Market Analysis) content
-- Bulk-loads M2-S6-C4 (Private / Consulting) and M2-S6-C5 (Government & Public Use),
-- 10 scenarios each (20 total).
--
-- Difficulty distribution per category:
--   #1, #2  · introductory
--   #3, #4  · basic
--   #5, #6  · intermediate
--   #7, #8  · advanced
--   #9, #10 · expert
--
-- After this migration:
--   - M2-S6-C4 (Private / Consulting) has 10 of 10 scenarios loaded.
--   - M2-S6-C5 (Government & Public Use) has 10 of 10 scenarios loaded.
--   - Section 6 is 5 of 6 categories complete.
--
-- No schema changes. The market_indicator_analysis field type and the
-- six M2-S6 categories were created in migration 017. M2-S6-C1 was
-- loaded in migration 018; M2-S6-C2 and M2-S6-C3 in migration 019;
-- this migration follows the same pattern.
--
-- Section-level defaults from migration 017:
--   classification_options = ['Improving','Stable','Declining','Market-Dependent']
--   min_rationale_chars    = 20
--   context_labels_by_category[M2-S6-C4] = 'Consulting Context'
--   context_labels_by_category[M2-S6-C5] = 'Government Context'
-- For self-describing scenario rows the per-scenario field_options_override
-- uses the more descriptive labels 'Private Consulting Context' and
-- 'Government & Public Use Context' (matching migration 019's pattern of
-- expanding 'Estate Context' to 'Estate & Tax Context' for the C3 rows).
--
-- Tables array shape:
--   Where the source artifact had a single data table, it is stored as a
--   one-element 'tables' array (the convention established in 018/019).
--
--   Where the source artifact had two data tables that share the SAME
--   indicator set across two markets (e.g. corridor + broader county;
--   rural + suburban), the rows are merged into a single wide-cols
--   tables[0] entry — matching the mig 018 C1 #9-10 and mig 019 C2 #9 /
--   C3 #9-10 pattern. Affected scenarios: C5 #5, C5 #6, C5 #8, C5 #9, C5 #10.
--
--   Where the source artifact had two or more data tables with
--   GENUINELY DIFFERENT indicator sets (e.g. for-sale indicators in one
--   table + rental/STR/cap-rate indicators in another), the migration
--   stores them as a multi-element 'tables' array, since there is no
--   meaningful way to merge non-overlapping indicator rows. This was
--   anticipated by mig 018's tables-array note ('later modules use
--   multi-element tables arrays for genuinely multi-dataset scenarios').
--   Affected scenarios: C4 #6, C4 #7, C4 #8, C4 #9, C4 #10 (3 tables),
--   C5 #7.
--
-- Idempotency: this migration runs once and is recorded in the
-- migration tracker by the migration runner.
-- ============================================================

BEGIN;

-- ============================================================
-- M2-S6-C4 — Private / Consulting (10 scenarios)
-- ============================================================

-- ─────────────────────────────────────────────────────
-- Scenario 1: 4411 Southport Road, Spartanburg — Buy-and-Hold Acquisition with Logistics Driver (Southport Crossing)
-- Category M2-S6-C4 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '4411 Southport Road, Spartanburg — Buy-and-Hold Acquisition with Logistics Driver (Southport Crossing)',
  'You are appraising the property at 4411 Southport Road, Spartanburg, SC 29306 (3BR/2BA, 1,680 SF, built 2008, ranch · Southport Crossing). Private investor acquisition analysis. Client is evaluating a single-family home for long-term buy-and-hold rental. Your analysis must address both for-sale market conditions and rental market signals relevant to the investment thesis. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C4';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject":{"address_summary":"4411 Southport Road, Spartanburg, SC 29306","subject_summary":"3BR/2BA, 1,680 SF, built 2008, ranch · Southport Crossing","school":"Spartanburg County School District 7","effective_date":"Current","context_label":"Private Consulting Context","context_text":"Private investor acquisition analysis. Client is evaluating a single-family home for long-term buy-and-hold rental. Your analysis must address both for-sale market conditions and rental market signals relevant to the investment thesis."},"tables":[{"label":"","cols":["Indicator","Prior 7-12 Months","Current 1-6 Months"],"rows":[["Closed Sales","34","42"],["Active Listings","11","6"],["Median Days on Market","29","16"],["Median Sale Price","$198,500","$211,800"],["List-to-Sale Price Ratio","98.4%","101.2%"],["Absorption Rate","4.1 months","2.1 months"],["Rental Vacancy Rate (comparable rentals, 1-mile radius)","8.2%","4.4%"]]}],"external":"New logistics facility announced in Moore area adding approximately 1,200 jobs in the $45K-$65K wage range, directly feeding demand for workforce rental and starter ownership housing in this corridor.","factors":[{"id":"abs","label":"Absorption rate trend"},{"id":"dom","label":"Days on market trend"},{"id":"lts","label":"List-to-sale price ratio trend"},{"id":"msp","label":"Median sale price trend"},{"id":"inv","label":"Active listing inventory level"},{"id":"rvr","label":"Rental vacancy rate trend"},{"id":"emp","label":"Employment and demand driver"},{"id":"cap","label":"Cap rate direction"},{"id":"sea","label":"Seasonal demand pattern"}],"net_conclusion":"Strong seller''s market with tightening rental demand. Both for-sale and rental indicators align. Acquisition thesis supported on both the appreciation and income dimensions.","commentary":"Scenario 1 establishes the private consulting context. Unlike GSE assignments, the investor client needs both for-sale market conditions AND rental market signals. The rental vacancy rate is a new indicator type - students must recognize it as a legitimate, required factor for an investor client even though it would not appear on a 1004MC.","classification_options":["Improving","Stable","Declining","Market-Dependent"],"min_rationale_chars":20}'::jsonb,
  '{"factors":{"abs":{"present":true,"classification":"Improving","rationale":"Dropped from 4.1 to 2.1 months - well into seller''s market territory. The single most important for-sale demand indicator for the acquisition analysis."},"dom":{"present":true,"classification":"Improving","rationale":"Fell from 29 to 16 days - demand accelerating. Faster absorption confirms buyer competition for available product."},"lts":{"present":true,"classification":"Improving","rationale":"Crossed above 100% (98.4 to 101.2%) - buyers bidding over asking price, a strong seller''s market confirmation."},"msp":{"present":true,"classification":"Improving","rationale":"+6.7% - meaningful appreciation confirming upward price pressure in the subject market."},"inv":{"present":true,"classification":"Improving","rationale":"Fell from 11 to 6 actives - constrained supply paired with rising demand supports the acquisition thesis."},"rvr":{"present":true,"classification":"Improving","rationale":"Dropped from 8.2% to 4.4% - tightening rental demand directly supports the buy-and-hold income thesis. A required investor indicator that does not appear on a 1004MC."},"emp":{"present":true,"classification":"Improving","rationale":"1,200 announced jobs in the subject wage band is a documented, verifiable demand driver with direct impact on both for-sale and rental demand."},"cap":{"present":false,"rationale":"No cap rate data was provided in this package. Do not cite indicators not evidenced in the data."},"sea":{"present":false,"rationale":"No seasonal data was provided. This is a distractor."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C4'
  AND s.order_index = 1;

